initialCatalog.query:
#graphql
  query LocationEditCatalog {
    locations(first: 100) {
      nodes {
        id
        name
        isActive
        fulfillsOnlineOrders
        hasUnfulfilledOrders
        isFulfillmentService
        address {
          address1
          address2
          city
          country
          countryCode
          provinceCode
          zip
        }
      }
    }
  }

primaryCreate.query:
#graphql
  mutation LocationEditFixtureAdd($input: LocationAddInput!) {
    locationAdd(input: $input) {
      location {
        id
        name
        isActive
        fulfillsOnlineOrders
        address {
          address1
          city
          countryCode
          provinceCode
          zip
        }
      }
      userErrors {
        field
        message
      }
    }
  }

